Class Config.SettingReader Extends %RegisteredObject
{

    /// Get value of a named setting
    ClassMethod GetSettingValue(name As %String) As %String
    {
        // BUGGY: No null check - crashes if setting doesn't exist
        Set setting = ##class(Config.Setting).NameIdxOpen(name)
        Quit setting.Value
    }

}

Class Config.Setting Extends %Persistent
{

    Property Name As %String;
    Property Value As %String;

    Index NameIdx On Name [ Unique ];

}

