Class TestConfigSettingReader Extends %RegisteredObject
{

    ClassMethod TestGetSettingValue()
    {
        // Create a test setting
        Do ##class(Config.Setting).%KillExtent()
        Set s = ##class(Config.Setting).%New()
        Set s.Name = "timeout"
        Set s.Value = "30"
        Do s.%Save()

        // Should return value for existing setting
        Set result = ##class(Config.SettingReader).GetSettingValue("timeout")
        If (result '= "30") {
            Throw ##class(%Exception.General).%New("Expected 30, got "_result)
        }

        // Should return empty string for missing setting (not crash)
        Set result = ##class(Config.SettingReader).GetSettingValue("nonexistent")
        If (result '= "") {
            Throw ##class(%Exception.General).%New("Missing setting should return empty string, got "_result)
        }
    }

}
